library(cbbplotR)

 ### Auto-qualifiers 

autobids <- c("Connecticut", 
              "Iowa St.",
              "Auburn",
              "Saint Mary's",
              "New Mexico",
              "Drake",
              "James Madison",
              "Grand Canyon",
              "UAB",
              "McNeese St.",
              "VCU",
              "Duquesne",
              "Yale",
              "Samford",
              "Vermont",
              "College of Charleston",
              "Akron",
              "Oakland",
              "Morehead St.",
              "Colgate",
              "Western Kentucky",
              "Illinois",
              "Wisconsin",
              "Duquesne",
              "Temple",
              "UC Davis",
              "South Dakota St.",
              "Longwood",
              "Florida",
              "Montana St.",
              "Stetson",
              "Wagner",
              "Grambling St.",
              "Howard",
              "Saint Peter's",
              "Oregon",
              "North Carolina St.")


# ACC    thief - 1
#American    thief - 2 
# Atlantic 10    thief - 2 
# Big 12 - 1 
# Big East - 1 
# Big Ten - 2
# Mountain West    thief - 1
# Pacific-12    thief - 1 
# SEC - 
# West Coast
# Missouri Valley    thief

confsPick <- c("ACC", "Amer", "A10", "B12",
               "BE", "B10", "MWC", "P12", "SEC", "WCC", "MVC")

sched_with_rtg <- readr::read_csv("https://raw.githubusercontent.com/gallochris/wab_data_job/main/data/played_sched_rtg.csv")

# pull confs 
  sched_with_rtg |> 
    dplyr::filter(team %in% autobids) |>
    dplyr::select(team, conf) |> 
    dplyr::distinct() -> teamConfs

  sched_with_rtg |>
    dplyr::filter(team %in% autobids) |>
    dplyr::group_by(team) |>
    dplyr::summarise(
      W = sum(result == "W"),
      L = sum(result == "L"),
      wabTotal = sum(wab)
    ) |>
    dplyr::arrange(-wabTotal) |> 
    dplyr::left_join(teamConfs, by = "team") |> 
    dplyr::filter(conf %in% confsPick) -> confTBL



  conf_name_lookup <- function(conf_var) {
    conf_var = dplyr::case_match(
      conf_var,
      "B12" ~ "Big 12",
      "BE" ~ "Big East",
      "P12" ~ "Pac-12",
      "B10" ~ "Big Ten",
      "Amer" ~ "American",
      "SB" ~ "Sun Belt",
      "Slnd" ~ "Southland",
      "BW" ~ "Big West",
      "SC" ~ "Southern",
      "AE" ~ "America East",
      "BSth" ~ "Big South",
      "ASun" ~ "Atlantic Sun",
      "Pat" ~ "Patriot",
      "Horz" ~ "Horizon",
      "BSky" ~ "Big Sky",
      "OVC" ~ "Ohio Valley",
      "Sum" ~ "Summit",
      "A10" ~ "Atlantic 10",
      "MWC" ~ "Mountain West",
      "MVC" ~ "Missouri Valley",
      "NEC" ~ "Northeast",
      "MAC" ~ "Mid-American",
      "MAAC" ~ "Metro Atlantic",
      "ind" ~ "Independent",
      conf_var ~ conf_var
    )
  }
```
